INSERT IGNORE INTO question_pool (cache_key, content, tts_content, category, model_answer, reference_type, is_active, created_at) VALUES
('SENIOR:SYSTEM_DESIGN', '팀 토폴로지(Team Topology)와 마이크로서비스 경계를 어떻게 정렬하나요?', '팀 토폴로지(Team Topology)와 마이크로서비스 경계를 어떻게 정렬하나요?', '마이크로서비스',
 '**Conway''s Law:**\n"조직이 설계하는 시스템은 그 조직의 커뮤니케이션 구조를 그대로 반영한다."\n→ 마이크로서비스 경계는 팀 구조와 정렬되어야 합니다.\n\n**Team Topology 4가지 팀 유형:**\n\n**1. Stream-Aligned Team (스트림 정렬 팀):**\n```\n비즈니스 도메인에 대한 E2E 책임\n예: 주문 팀 → 주문 서비스 전체 (BE + FE + DB)\n→ 해당 도메인 마이크로서비스 소유\n```\n\n**2. Platform Team (플랫폼 팀):**\n```\n다른 팀이 쉽게 개발/배포할 수 있는 기반 제공\n예: Kubernetes 클러스터, CI/CD 파이프라인, 모니터링\n→ 공통 인프라 서비스\n```\n\n**3. Enabling Team (지원 팀):**\n```\n특정 기술/역량을 다른 팀에 전파\n예: 보안 팀, DDD 전문가 팀\n→ 일시적 지원, 독립 서비스 없음\n```\n\n**4. Complicated Subsystem Team (복잡 서브시스템 팀):**\n```\n고도로 전문화된 기술이 필요한 서비스\n예: 추천 알고리즘 팀, 실시간 분석 팀\n→ 특수 목적 서비스\n```\n\n**DDD Bounded Context와의 정렬:**\n```\n[주문 도메인 (Bounded Context)]\n    ↕ 정렬\n[주문 팀 (Stream-Aligned)]\n    ↕ 소유\n[주문 서비스 + 주문 DB]\n```\n\n**팀 간 인터랙션 모드:**\n- Collaboration: 긴밀 협업 (임시, 신규 서비스 설계)\n- X-as-a-Service: API로 사용 (플랫폼 팀 제공)\n- Facilitating: 지식 전파 (지원 팀)\n\n**역 Conway 조작 (Reverse Conway Maneuver):**\n원하는 아키텍처에 맞게 팀을 먼저 재구성 → 자연스럽게 원하는 시스템 구조 나타남',
 'MODEL_ANSWER', TRUE, NOW());

INSERT IGNORE INTO question_pool (cache_key, content, tts_content, category, model_answer, reference_type, is_active, created_at) VALUES
('SENIOR:SYSTEM_DESIGN', '마이크로서비스에서 데이터 일관성을 유지하는 패턴들을 비교하고 상황별 선택 기준을 제시해주세요.', '마이크로서비스에서 데이터 일관성을 유지하는 패턴들을 비교하고 상황별 선택 기준을 제시해주세요.', '마이크로서비스',
 '**마이크로서비스 데이터 일관성의 어려움:**\n각 서비스가 독립 DB를 가지므로 ACID 트랜잭션 불가. 분산 환경에서 일관성 유지 패턴이 필요합니다.\n\n**패턴 1: Two-Phase Commit (2PC)**\n```\n[Coordinator]\n1단계(Prepare): 모든 서비스에 트랜잭션 준비 요청\n    → 서비스들: "준비 완료" 응답\n2단계(Commit): 모든 준비 확인 후 커밋 명령\n    → 서비스들: 실제 커밋\n```\n장점: 강한 일관성\n단점: Coordinator SPOF, 느림, 마이크로서비스에서 잘 사용 안 함\n\n**패턴 2: Saga 패턴**\n```\n각 서비스가 로컬 트랜잭션 + 보상 트랜잭션\n실패 시 역순으로 보상 실행 (롤백 유사)\n→ 결과적 일관성\n```\n\n**패턴 3: Outbox + CDC**\n```\nDB 트랜잭션과 이벤트 발행의 원자성 보장\n→ 비즈니스 로직 + 이벤트를 같은 트랜잭션으로\n```\n\n**패턴 4: CQRS + Event Sourcing**\n```\n모든 상태 변경을 이벤트로 → 다양한 Read Model 생성\n→ 읽기 일관성은 Eventual\n```\n\n**상황별 선택:**\n| 상황 | 패턴 | 이유 |\n|------|------|------|\n| 결제 + 재고 원자적 처리 | Saga (Orchestration) | 보상 트랜잭션 명확 |\n| 이벤트 유실 방지 | Outbox + CDC | DB 트랜잭션 보장 |\n| 복잡한 읽기 쿼리 | CQRS | 읽기 모델 최적화 |\n| 완전한 감사 로그 | Event Sourcing | 모든 변경 이력 보존 |\n\n**보상 트랜잭션 설계 원칙:**\n- 모든 비즈니스 트랜잭션에 보상 정의 필수\n- 보상도 실패 가능 → 재시도 + 수동 개입 절차\n- 멱등성 보장 필수',
 'MODEL_ANSWER', TRUE, NOW());

INSERT IGNORE INTO question_pool (cache_key, content, tts_content, category, model_answer, reference_type, is_active, created_at) VALUES
('SENIOR:SYSTEM_DESIGN', 'Kubernetes 환경에서 마이크로서비스 운영 시 핵심 설계 패턴을 설명해주세요.', '쿠버네티스 환경에서 마이크로서비스 운영 시 핵심 설계 패턴을 설명해주세요.', '마이크로서비스',
 '**Kubernetes 기반 마이크로서비스 핵심 패턴:**\n\n**1. 헬스 체크 정밀 설계:**\n```yaml\nlivenessProbe:      # 재시작 여부 결정\n  httpGet:\n    path: /actuator/health/liveness\n    port: 8080\n  initialDelaySeconds: 30\n  periodSeconds: 10\n\nreadinessProbe:     # 트래픽 수신 가능 여부\n  httpGet:\n    path: /actuator/health/readiness  # DB, Redis 연결 포함\n    port: 8080\n  initialDelaySeconds: 20\n  periodSeconds: 5\n\nstartupProbe:       # 느린 시작 허용 (JVM 워밍업)\n  httpGet:\n    path: /actuator/health\n    port: 8080\n  failureThreshold: 30\n  periodSeconds: 10\n```\n\n**2. 그레이스풀 셧다운:**\n```yaml\nspec:\n  terminationGracePeriodSeconds: 60\n  containers:\n  - lifecycle:\n      preStop:\n        exec:\n          command: ["sh", "-c", "sleep 5"]  # 로드밸런서 제거 대기\n```\n\n**3. 리소스 제한 (Resource Limits):**\n```yaml\nresources:\n  requests:    # 스케줄링 기준\n    memory: "256Mi"\n    cpu: "250m"\n  limits:      # 최대 사용량\n    memory: "512Mi"\n    cpu: "500m"\n# requests != limits → Burstable QoS\n# JVM 서비스: limits.memory = Xmx + 헤드룸 (20%)\n```\n\n**4. Pod Disruption Budget (PDB):**\n```yaml\napiVersion: policy/v1\nkind: PodDisruptionBudget\nspec:\n  minAvailable: 2  # 업그레이드 중 최소 2개 유지\n  selector:\n    matchLabels:\n      app: order-service\n```\n\n**5. 수평 Pod 자동 확장 (HPA):**\n```yaml\nspec:\n  metrics:\n  - type: External\n    external:\n      metric:\n        name: kafka_consumer_lag\n      target:\n        type: AverageValue\n        averageValue: "1000"  # 파티션당 Lag 1000 초과 시 확장\n```\n\n**6. 시크릿 관리:**\n```\n환경변수 직접 주입 금지\n→ Kubernetes Secret + Vault Agent Sidecar\n→ 또는 AWS Secrets Manager + External Secrets Operator\n```',
 'MODEL_ANSWER', TRUE, NOW());

INSERT IGNORE INTO question_pool (cache_key, content, tts_content, category, model_answer, reference_type, is_active, created_at) VALUES
('SENIOR:SYSTEM_DESIGN', '마이크로서비스 보안 아키텍처에서 Zero Trust 모델을 어떻게 구현하나요?', '마이크로서비스 보안 아키텍처에서 Zero Trust 모델을 어떻게 구현하나요?', '마이크로서비스',
 '**Zero Trust 원칙:**\n"아무것도 신뢰하지 않는다 — 내부 네트워크라도 검증 후 접근"\n기존 경계 보안(방화벽 안 = 신뢰)의 한계 극복.\n\n**Zero Trust 핵심 원칙:**\n1. 항상 검증 (Verify Explicitly)\n2. 최소 권한 접근 (Least Privilege Access)\n3. 침해 가정 (Assume Breach)\n\n**구현 요소:**\n\n**1. 서비스 간 mTLS (상호 TLS):**\n```\n기존: 서비스A → 서비스B (인증 없음, IP만 확인)\nZero Trust: 서비스A ←→ 서비스B (양방향 인증서 검증)\n\n구현:\n- Istio Service Mesh: 자동 mTLS 적용\n- SPIFFE/SPIRE: 서비스 ID 인증서 자동 발급/갱신\n```\n\n**2. 워크로드 ID (Workload Identity):**\n```\nKubernetes Service Account → OIDC 토큰 발급\n→ AWS IAM Role for Service Account (IRSA)\n→ 각 서비스가 필요한 AWS 리소스만 접근 가능\n\nexample:\norder-service Service Account\n→ IAM Role: order-service-role\n→ S3 특정 버킷 Read Only 권한만\n```\n\n**3. 네트워크 정책 (Network Policy):**\n```yaml\napiVersion: networking.k8s.io/v1\nkind: NetworkPolicy\nspec:\n  podSelector:\n    matchLabels:\n      app: payment-service\n  ingress:\n  - from:\n    - podSelector:\n        matchLabels:\n          app: order-service  # order-service에서만 수신\n  egress:\n  - to:\n    - podSelector:\n        matchLabels:\n          app: payment-db  # payment-db로만 송신\n```\n\n**4. 동적 시크릿 (Dynamic Secrets):**\n```\nHashiCorp Vault:\n→ DB 접근 자격증명을 짧은 TTL(1시간)로 동적 발급\n→ 시크릿 노출 시 자동 만료 → 피해 최소화\n```\n\n**5. API 접근 감사:**\n```\n모든 API 호출 로깅: 누가, 언제, 어떤 리소스에\n이상 행동 탐지: 비정상적 접근 패턴 알림\n```',
 'MODEL_ANSWER', TRUE, NOW());

INSERT IGNORE INTO question_pool (cache_key, content, tts_content, category, model_answer, reference_type, is_active, created_at) VALUES
('SENIOR:SYSTEM_DESIGN', '마이크로서비스의 테스트 전략과 테스트 피라미드를 어떻게 설계하나요?', '마이크로서비스의 테스트 전략과 테스트 피라미드를 어떻게 설계하나요?', '마이크로서비스',
 '**마이크로서비스 테스트 피라미드:**\n```\n        [E2E 테스트]         ← 소수, 느림, 고비용\n      [통합 테스트]           ← 중간\n    [컨트랙트 테스트]          ← 서비스 간 계약 검증\n  [컴포넌트 테스트]            ← 서비스 단위 격리\n[단위 테스트]                  ← 다수, 빠름, 저비용\n```\n\n**1. 단위 테스트 (Unit Test):**\n```java\n// 순수 비즈니스 로직, 외부 의존성 Mock\n@ExtendWith(MockitoExtension.class)\nclass OrderServiceTest {\n    @Mock OrderRepository orderRepository;\n    @InjectMocks OrderService orderService;\n\n    @Test\n    void 재고_부족_시_주문_실패() {\n        when(inventoryClient.getStock(1L)).thenReturn(0);\n        assertThrows(InsufficientStockException.class,\n            () -> orderService.createOrder(request));\n    }\n}\n```\n\n**2. 컨트랙트 테스트 (Contract Test — Pact):**\n```java\n// Consumer가 기대하는 응답을 계약으로 정의\n// Provider 변경 시 계약 위반 자동 감지\n@PactTestFor(providerName = "order-service")\nclass OrderConsumerContractTest {\n    @Pact(consumer = "payment-service")\n    public RequestResponsePact createPact(PactDslWithProvider builder) {\n        return builder\n            .uponReceiving("주문 조회")\n            .path("/orders/1")\n            .method("GET")\n            .willRespondWith()\n            .status(200)\n            .body(new PactDslJsonBody()\n                .numberValue("id", 1)\n                .stringValue("status", "CONFIRMED"))\n            .toPact();\n    }\n}\n```\n\n**3. 컴포넌트 테스트 (서비스 격리):**\n```java\n// 실제 Spring Context, 외부 서비스는 WireMock으로 대체\n@SpringBootTest\n@AutoConfigureWireMock\nclass OrderComponentTest {\n    // Kafka, 외부 API → WireMock\n    // DB → Testcontainers (실제 MySQL)\n}\n```\n\n**4. Testcontainers 활용:**\n```java\n@Testcontainers\nclass OrderRepositoryTest {\n    @Container\n    static MySQLContainer<?> mysql = new MySQLContainer<>("mysql:8.0");\n    @Container\n    static GenericContainer<?> redis = new GenericContainer<>("redis:7");\n}\n```\n\n**5. E2E 테스트 범위 최소화:**\n- 핵심 사용자 여정 5~10개만 (로그인 → 주문 → 결제)\n- 야간 배치로 실행 (속도 < 신뢰성)',
 'MODEL_ANSWER', TRUE, NOW());

INSERT IGNORE INTO question_pool (cache_key, content, tts_content, category, model_answer, reference_type, is_active, created_at) VALUES
('SENIOR:SYSTEM_DESIGN', '대규모 마이크로서비스 환경에서 카오스 엔지니어링(Chaos Engineering)을 어떻게 도입하나요?', '대규모 마이크로서비스 환경에서 카오스 엔지니어링(Chaos Engineering)을 어떻게 도입하나요?', '마이크로서비스',
 '**카오스 엔지니어링 정의:**\n"프로덕션 환경에서 의도적으로 장애를 주입하여 시스템의 회복 탄력성을 사전에 검증하는 방법론"\n— Netflix의 Chaos Monkey에서 시작\n\n**도입 원칙 (GameDay):**\n```\n1. 정상 상태 정의 (Steady State)\n   예: 에러율 < 0.1%, P99 레이턴시 < 200ms\n\n2. 가설 수립\n   "결제 서비스 장애 시 주문 서비스는 서킷 브레이커로 빠른 실패하고\n   주문은 보류 상태로 저장되어야 한다"\n\n3. 통제된 장애 주입\n4. 결과 관찰 및 검증\n5. 취약점 발견 시 개선\n```\n\n**장애 주입 유형:**\n```\n인프라 레벨:\n- Pod/Node 종료 (Chaos Monkey)\n- 네트워크 레이턴시 추가 (tc netem)\n- 네트워크 패킷 손실\n- 디스크 I/O 고갈\n\n애플리케이션 레벨:\n- 특정 API 응답 지연\n- 에러 응답 반환\n- 메모리 고갈 (Memory Hog)\n- CPU 고갈\n\n데이터 레벨:\n- DB Failover\n- 캐시 플러시\n```\n\n**Chaos Mesh (Kubernetes):**\n```yaml\napiVersion: chaos-mesh.org/v1alpha1\nkind: NetworkChaos\nspec:\n  action: delay\n  duration: "30s"\n  selector:\n    namespaces: ["production"]\n    labelSelectors:\n      app: payment-service\n  delay:\n    latency: "100ms"\n    jitter: "50ms"\n```\n\n**AWS Fault Injection Simulator (FIS):**\n```\nEC2 종료, RDS Failover, ECS 태스크 종료 등\nAWS 네이티브 카오스 실험\n```\n\n**안전 장치:**\n- Abort 조건 정의 (에러율 > 5% 시 자동 중단)\n- 비즈니스 시간 외 실행\n- 점진적 폭발 반경 확대 (dev → staging → prod)\n- 관련 팀 사전 공지\n\n**성숙도 모델:**\n1. Dev 환경 카오스\n2. Staging 환경 게임데이\n3. 프로덕션 소규모 카오스\n4. 프로덕션 지속적 카오스 (Netflix 수준)',
 'MODEL_ANSWER', TRUE, NOW());

