INSERT IGNORE INTO question_pool (cache_key, content, tts_content, category, model_answer, reference_type, is_active, created_at) VALUES
('SENIOR:SYSTEM_DESIGN', 'API 게이트웨이 패턴과 BFF(Backend for Frontend) 패턴을 언제 선택하나요?', '에이피아이 게이트웨이 패턴과 비에프에프(Backend for Frontend) 패턴을 언제 선택하나요?', 'API설계',
 '**API Gateway 패턴:**\n모든 클라이언트(웹, 앱, IoT)가 동일한 단일 Gateway를 사용.\n\n```\n[웹 클라이언트]\n[iOS 앱]         →  [API Gateway]  →  [마이크로서비스들]\n[Android 앱]\n[IoT 기기]\n```\n\n**단점:**\n- 다양한 클라이언트 요구사항을 하나의 Gateway가 처리 → 복잡도 증가\n- 모바일 앱은 데이터 절약 중요, 웹은 풍부한 데이터 필요\n- Gateway 변경이 모든 클라이언트에 영향\n\n**BFF (Backend for Frontend) 패턴:**\n클라이언트 유형별로 전용 Backend를 운영.\n\n```\n[웹 클라이언트]    → [Web BFF]     → [마이크로서비스들]\n[iOS 앱]           → [Mobile BFF]  → [마이크로서비스들]\n[Android 앱]       → [Mobile BFF]\n[파트너 API]        → [Partner BFF] → [마이크로서비스들]\n```\n\n**BFF 장점:**\n- 각 클라이언트에 최적화된 응답 구성\n- 클라이언트 팀이 BFF를 직접 운영 가능\n- 클라이언트별 독립 배포\n- 불필요한 데이터 전송 제거 (모바일 최적화)\n\n**BFF 단점:**\n- 코드 중복 (여러 BFF에서 비슷한 로직)\n- 운영할 서비스 수 증가\n\n**실무 조합:**\n```\n[API Gateway] — 인증, Rate Limiting, SSL 종료\n    ↓\n[Web BFF]  /  [Mobile BFF]  /  [Partner BFF]\n    ↓                ↓                  ↓\n           [마이크로서비스들]\n```\n\n**GraphQL을 BFF로:**\n```\n[Web BFF = GraphQL]\n→ 클라이언트가 필요한 필드만 요청\n→ 여러 서비스 데이터를 단일 쿼리로 조합\n→ 오버패칭/언더패칭 해결\n```\n\n**선택 기준:**\n- 클라이언트 1~2개, 요구사항 유사 → API Gateway로 충분\n- 다양한 클라이언트, 요구사항 상이 → BFF\n- 팀이 클라이언트별로 분리 → BFF (Conway''s Law)',
 'MODEL_ANSWER', TRUE, NOW());

INSERT IGNORE INTO question_pool (cache_key, content, tts_content, category, model_answer, reference_type, is_active, created_at) VALUES
('SENIOR:SYSTEM_DESIGN', 'gRPC와 Protocol Buffers를 사용한 서비스 간 통신 설계 시 고려사항은?', '지알피씨와 프로토콜 버퍼스를 사용한 서비스 간 통신 설계 시 고려사항은?', 'API설계',
 '**gRPC 특성:**\n```\nHTTP/2 기반 + Protocol Buffers 직렬화\n→ REST보다 3~10배 빠른 성능\n→ 양방향 스트리밍 지원\n→ 강타입 계약 (코드 생성)\n```\n\n**Protocol Buffers 스키마:**\n```protobuf\n// order.proto\nsyntax = "proto3";\npackage order;\n\nservice OrderService {\n  rpc GetOrder (GetOrderRequest) returns (Order);\n  rpc CreateOrder (CreateOrderRequest) returns (Order);\n  rpc StreamOrders (StreamRequest) returns (stream Order); // 서버 스트리밍\n  rpc BatchCreateOrders (stream CreateOrderRequest) returns (BatchResult); // 클라이언트 스트리밍\n}\n\nmessage Order {\n  int64 id = 1;\n  int64 user_id = 2;\n  OrderStatus status = 3;\n  double amount = 4;\n  google.protobuf.Timestamp created_at = 5;\n}\n\nenum OrderStatus {\n  PENDING = 0;\n  CONFIRMED = 1;\n  SHIPPED = 2;\n}\n```\n\n**Java 서버 구현:**\n```java\n@GrpcService\npublic class OrderGrpcService extends OrderServiceGrpc.OrderServiceImplBase {\n    @Override\n    public void getOrder(GetOrderRequest req, StreamObserver<Order> observer) {\n        try {\n            Order order = orderService.findById(req.getId());\n            observer.onNext(order);\n            observer.onCompleted();\n        } catch (Exception e) {\n            observer.onError(Status.NOT_FOUND\n                .withDescription("Order not found: " + req.getId())\n                .asException());\n        }\n    }\n}\n```\n\n**스키마 진화 규칙:**\n```\n안전한 변경:\n+ 새 필드 추가 (새 필드 번호)\n+ 선택적 필드를 반복 필드로\n\n위험한 변경:\n- 필드 번호 변경 (역직렬화 오류)\n- 필드 타입 변경\n- 필드 번호 재사용 (삭제된 번호)\n\n안전한 삭제:\n1. 필드 사용 중단 (deprecated)\n2. reserved로 번호 예약\nreserved 3, 4;  // 삭제된 필드 번호 예약\nreserved "old_field_name";\n```\n\n**gRPC vs REST 선택:**\n| 상황 | gRPC | REST |\n|------|------|------|\n| 내부 서비스 통신 | ✅ | |\n| 외부 공개 API | | ✅ |\n| 실시간 스트리밍 | ✅ | |\n| 브라우저 클라이언트 | △ (gRPC-Web) | ✅ |\n| 대역폭 제한 환경 | ✅ | |',
 'MODEL_ANSWER', TRUE, NOW());

INSERT IGNORE INTO question_pool (cache_key, content, tts_content, category, model_answer, reference_type, is_active, created_at) VALUES
('SENIOR:SYSTEM_DESIGN', 'API 관리(API Management)와 개발자 포털(Developer Portal)을 어떻게 설계하나요?', '에이피아이 관리(에이피아이 Management)와 개발자 포털(Developer Portal)을 어떻게 설계하나요?', 'API설계',
 '**API 관리의 필요성:**\n외부 파트너/개발자에게 API를 제공할 때 보안, 사용량 제어, 문서화, 모니터링을 체계적으로 관리.\n\n**API 관리 핵심 기능:**\n\n**1. API Key 발급 및 관리:**\n```\n파트너 등록 → API Key 발급 (UUID v4)\n→ Key별 Rate Limit 설정\n→ Key별 허용 API 범위 설정 (Scope)\n→ Key 만료/재발급/폐기\n```\n\n**2. 사용량 제어 (Quota & Throttling):**\n```\n기본 티어: 1,000 req/day\n스탠다드 티어: 100,000 req/day\n엔터프라이즈 티어: 무제한\n\n초과 시: 429 Too Many Requests\nRetry-After: {reset_timestamp}\n```\n\n**3. API 버전 수명주기:**\n```\nAlpha → Beta → GA (General Availability) → Deprecated → Sunset\n\nDeprecation 정책:\n- 최소 6개월 전 공지\n- Sunset 헤더로 만료일 명시\n- 마이그레이션 가이드 제공\n```\n\n**4. 개발자 포털 구성:**\n```\n[개발자 포털 필수 요소]\n├── API 레퍼런스 (OpenAPI/Swagger 자동 생성)\n├── 시작하기 가이드 (Quickstart)\n├── 코드 샘플 (Java, Python, JS, Go)\n├── 대화형 API 탐색기 (Try It)\n├── SDK 다운로드\n├── 변경 로그 (Changelog)\n├── 상태 페이지 (Status Page)\n└── 커뮤니티 포럼\n```\n\n**5. OpenAPI 스펙 자동 생성 (Spring):**\n```java\n@Operation(summary = "주문 조회", description = "주문 ID로 상세 정보 조회")\n@ApiResponses({\n    @ApiResponse(responseCode = "200", description = "성공"),\n    @ApiResponse(responseCode = "404", description = "주문 없음")\n})\n@GetMapping("/orders/{id}")\npublic OrderResponse getOrder(@PathVariable Long id) { ... }\n```\n\n**6. 모니터링 대시보드 (파트너 제공):**\n```\n파트너별 사용량, 에러율, 레이턴시 리포트\n월별 청구서 연동\n```\n\n**솔루션:** AWS API Gateway + Developer Portal, Kong Enterprise, Azure API Management',
 'MODEL_ANSWER', TRUE, NOW());

INSERT IGNORE INTO question_pool (cache_key, content, tts_content, category, model_answer, reference_type, is_active, created_at) VALUES
('SENIOR:SYSTEM_DESIGN', 'API 설계에서 도메인 주도 설계(DDD)를 어떻게 반영하나요?', '에이피아이 설계에서 도메인 주도 설계(디디디)를 어떻게 반영하나요?', 'API설계',
 '**DDD와 API 설계의 연결:**\nDDD의 Bounded Context, Aggregate, 유비쿼터스 언어를 API 설계에 직접 반영.\n\n**Bounded Context → API 경계:**\n```\n[주문 컨텍스트]   → /api/orders/...\n[결제 컨텍스트]   → /api/payments/...\n[배송 컨텍스트]   → /api/shipments/...\n[카탈로그 컨텍스트] → /api/catalog/...\n\n각 컨텍스트는 독립 서비스 = 독립 API\n```\n\n**Aggregate를 API 자원으로:**\n```\n주문 Aggregate Root: Order (OrderItem, Payment를 포함)\n\nAPI 설계:\nPOST /orders                    — 주문 생성 (Aggregate 전체)\nGET  /orders/{id}               — 주문 조회 (Aggregate 전체)\nPOST /orders/{id}/confirm       — 주문 확정 (도메인 이벤트)\nPOST /orders/{id}/cancel        — 주문 취소 (도메인 이벤트)\n\n// NOT: /orders/{id}/items/{itemId} — Aggregate 내부 직접 접근 지양\n```\n\n**유비쿼터스 언어 → API 명명:**\n```\n비즈니스 용어를 그대로 API에 반영\n\n나쁜 예:\nPOST /orders/{id}/status (status=CONFIRMED)\n\n좋은 예:\nPOST /orders/{id}/confirm\nPOST /orders/{id}/cancel\nPOST /orders/{id}/ship\n→ 도메인 전문가와 개발자가 같은 언어 사용\n```\n\n**도메인 이벤트 기반 API:**\n```\n명령(Command): POST /orders/{id}/place\n→ 내부에서 OrderPlaced 이벤트 발행\n→ 외부 시스템은 이벤트 구독\n\n이벤트 웹훅 등록:\nPOST /webhooks\n{ event: "order.placed", url: "https://..." }\n```\n\n**컨텍스트 맵 → API 통합 패턴:**\n```\nShared Kernel: 두 컨텍스트가 공유 모델 사용\nCustomer/Supplier: 상류(주문)가 하류(배송) 요구사항에 맞춤\nAnticorruption Layer: 레거시 시스템과 경계에서 변환\n```\n\n**DTO와 도메인 객체 분리:**\n```java\n// API DTO — 외부 계약\npublic record OrderResponse(\n    Long id, String status, BigDecimal amount\n) {}\n\n// 도메인 객체 — 내부 로직\npublic class Order {\n    private OrderStatus status; // 내부 열거형\n    private Money amount;       // 값 객체\n    public void confirm() { ... }  // 도메인 로직\n}\n// 변환은 Application Service에서 담당\n```',
 'MODEL_ANSWER', TRUE, NOW());

INSERT IGNORE INTO question_pool (cache_key, content, tts_content, category, model_answer, reference_type, is_active, created_at) VALUES
('SENIOR:SYSTEM_DESIGN', '대규모 서비스에서 API 성능 최적화를 위한 전략을 종합적으로 설명해주세요.', '대규모 서비스에서 에이피아이 성능 최적화를 위한 전략을 종합적으로 설명해주세요.', 'API설계',
 '**API 성능 병목 분류:**\n```\n1. 네트워크 레이턴시\n2. 직렬화/역직렬화 비용\n3. DB 쿼리 성능\n4. 서비스 간 호출 레이턴시\n5. 애플리케이션 로직 처리 시간\n```\n\n**1. 연결 최적화:**\n```\nHTTP/2: 다중화(Multiplexing) — 동일 연결로 여러 요청 병렬\nHTTP/3 (QUIC): UDP 기반, 헤드오브라인 블로킹 제거\nKeep-Alive: 연결 재사용\nConnectionPool: DB, Redis 연결 풀 적절히 설정\n```\n\n**2. 응답 크기 최적화:**\n```\n압축: gzip/Brotli (60~80% 크기 감소)\nContent-Encoding: gzip\n\nField Filtering:\nGET /users/1?fields=id,name,email\n→ 필요한 필드만 반환\n\nSparse Fieldsets (JSON:API):\nGET /articles?fields[articles]=title,body\n```\n\n**3. 동시성 최적화:**\n```java\n// 독립적인 서비스 호출을 병렬로\nCompletableFuture<User> userFuture =\n    CompletableFuture.supplyAsync(() -> userService.get(userId));\nCompletableFuture<List<Order>> ordersFuture =\n    CompletableFuture.supplyAsync(() -> orderService.getByUser(userId));\n\nCompletableFuture.allOf(userFuture, ordersFuture).join();\nUser user = userFuture.get();\nList<Order> orders = ordersFuture.get();\n// 순차 호출 200ms+150ms=350ms → 병렬 200ms\n```\n\n**4. 캐싱 레이어:**\n```\nHTTP 캐싱:\nCache-Control: public, max-age=60\nETag: "abc123"\nIf-None-Match: "abc123" → 304 Not Modified (바디 전송 없음)\n\nConditional Request:\nIf-Modified-Since: 변경 없으면 304 → 대역폭 절약\n```\n\n**5. 페이지네이션 + 부분 응답:**\n```\nCursor 기반 페이지네이션 (Keyset)\nGET /orders?after=1234&limit=20\n→ WHERE id > 1234 LIMIT 20 (OFFSET보다 빠름)\n```\n\n**6. N+1 방지:**\n```java\n// 나쁜 예: N+1\norders.forEach(o -> o.setUser(userService.get(o.getUserId())));\n\n// 좋은 예: 배치 조회\nSet<Long> userIds = orders.stream()\n    .map(Order::getUserId).collect(toSet());\nMap<Long, User> users = userService.findAllById(userIds);\norders.forEach(o -> o.setUser(users.get(o.getUserId())));\n```\n\n**성능 측정 기준:**\n- P50, P95, P99 레이턴시\n- Apdex Score (응답 시간 만족도 지수)\n- 서비스별 SLO 대비 현재 지표',
 'MODEL_ANSWER', TRUE, NOW());

INSERT IGNORE INTO question_pool (cache_key, content, tts_content, category, model_answer, reference_type, is_active, created_at) VALUES
('SENIOR:SYSTEM_DESIGN', 'API 보안 설계에서 OWASP API Security Top 10을 기반으로 방어 전략을 설명해주세요.', '에이피아이 보안 설계에서 오와에스피 에이피아이 Security Top 10을 기반으로 방어 전략을 설명해주세요.', 'API설계',
 '**OWASP API Security Top 10 (2023) 주요 항목과 방어:**\n\n**1. Broken Object Level Authorization (BOLA/IDOR)**\n```\n공격: GET /orders/1234 → 다른 사용자 주문 조회\n\n방어:\n// 반드시 소유자 검증\npublic Order getOrder(Long orderId, Long requestingUserId) {\n    Order order = orderRepository.findById(orderId);\n    if (!order.getUserId().equals(requestingUserId)) {\n        throw new ForbiddenException();\n    }\n    return order;\n}\n// URL에 리소스 ID를 노출하기보다 JWT에서 userId 추출\n```\n\n**2. Broken Authentication**\n```\n방어:\n- JWT 서명 검증 필수 (alg:none 공격 방지)\n- 토큰 만료 검증\n- Refresh Token Rotation\n- 브루트포스 방어 (Rate Limiting + 계정 잠금)\n```\n\n**3. Broken Object Property Level Authorization**\n```\n공격: PATCH /users/1 { "role": "ADMIN" } — 권한 상승\n\n방어:\n@JsonIgnore private String role;  // 직접 바인딩 금지\n// DTO로 허용 필드만 명시적 수용\n```\n\n**4. Unrestricted Resource Consumption**\n```\n방어:\n- Rate Limiting (IP별, API Key별)\n- 요청 크기 제한 (max-body-size: 10MB)\n- 응답 타임아웃 설정\n- 페이지네이션으로 대용량 응답 제한\n```\n\n**5. Broken Function Level Authorization**\n```\n공격: 일반 사용자가 /admin/users 접근\n\n방어:\n@PreAuthorize("hasRole(''ADMIN'')")\n@GetMapping("/admin/users")\n// 모든 관리자 엔드포인트 명시적 인가\n```\n\n**6. Mass Assignment**\n```\n공격: POST /users { "name": "홍", "isAdmin": true }\n\n방어:\n// Request DTO에 허용 필드만\npublic record CreateUserRequest(\n    @NotBlank String name,\n    @Email String email\n    // isAdmin, role 등 민감 필드 제외\n) {}\n```\n\n**7. Security Misconfiguration**\n```\n방어:\n- CORS 화이트리스트 설정\n- 불필요한 HTTP 메서드 비활성화\n- 에러 응답에 스택 트레이스 제거\n- HTTPS Only\n```\n\n**8. SQL/NoSQL Injection**\n```java\n// JPA 파라미터 바인딩 (안전)\n@Query("SELECT u FROM User u WHERE u.email = :email")\nUser findByEmail(@Param("email") String email);\n// 절대 문자열 연결 금지\n```\n\n**9. Improper Assets Management**\n```\n방어:\n- API 인벤토리 관리 (모든 엔드포인트 문서화)\n- 구버전 API Sunset 정책 준수\n- Shadow API (문서화 안 된 API) 탐지\n```\n\n**10. Insufficient Logging & Monitoring**\n```java\n// 모든 인증 실패, 권한 오류, 이상 요청 로깅\nlog.warn("인가 실패: userId={}, resource={}, action={}", \n         userId, resource, action);\n// SIEM 연동으로 이상 패턴 실시간 탐지\n```',
 'MODEL_ANSWER', TRUE, NOW());
